import React from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';

const StocksContainer = styled.div`
  max-width: 1400px;
  margin: 0 auto;
  padding: 2rem 0;
`;

const PageHeader = styled(motion.div)`
  margin-bottom: 6rem;
  text-align: center;

  h1 {
    font-size: 5rem;
    font-weight: 950;
    letter-spacing: -4px;
    margin-bottom: 1.5rem;
    background: linear-gradient(135deg, #00f2fe 0%, #4facfe 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    text-transform: uppercase;
    line-height: 1;
  }

  p {
    color: ${props => props.theme.colors.textSecondary};
    font-size: 1.2rem;
    max-width: 600px;
    margin: 0 auto;
    letter-spacing: 1px;
    font-weight: 500;
  }
`;

const SectorsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 2.5rem;

  @media (max-width: 1100px) {
    grid-template-columns: repeat(2, 1fr);
  }

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
`;

const SectorCard = styled(motion.div)`
  background: rgba(15, 15, 20, 0.4);
  backdrop-filter: blur(24px);
  border-radius: 40px;
  padding: 3rem;
  border: 1px solid rgba(255, 255, 255, 0.05);
  cursor: pointer;
  transition: ${props => props.theme.transitions.default};
  position: relative;
  overflow: hidden;
  display: flex;
  flex-direction: column;
  gap: 2rem;

  &:hover {
    transform: translateY(-12px);
    border-color: rgba(0, 242, 254, 0.3);
    background: rgba(255, 255, 255, 0.05);
    box-shadow: 0 20px 40px -10px rgba(0, 0, 0, 0.5);
  }

  &::before {
    content: '';
    position: absolute;
    top: 0;
    right: 0;
    width: 200px;
    height: 200px;
    background: radial-gradient(circle, rgba(0, 242, 254, 0.1) 0%, transparent 70%);
    z-index: -1;
  }
`;

const SectorHeader = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
`;

const SectorIcon = styled.div`
  font-size: 3rem;
  background: rgba(255, 255, 255, 0.03);
  width: 80px;
  height: 80px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 24px;
  border: 1px solid rgba(255, 255, 255, 0.05);
  filter: drop-shadow(0 0 10px rgba(0, 242, 254, 0.2));
`;

const SectorName = styled.h2`
  font-size: 1.8rem;
  color: ${props => props.theme.colors.textPrimary};
  font-weight: 900;
  letter-spacing: -1px;
  text-transform: uppercase;
`;

const SectorDescription = styled.p`
  color: ${props => props.theme.colors.textSecondary};
  font-size: 1rem;
  line-height: 1.6;
  flex-grow: 1;
  font-weight: 500;
`;

const SectorStats = styled.div`
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.5rem;
  padding-top: 2rem;
  border-top: 1px solid rgba(255, 255, 255, 0.05);
`;

const StatItem = styled.div`
  display: flex;
  flex-direction: column;
  gap: 6px;

  .value {
    font-size: 1.2rem;
    font-weight: 900;
    color: ${props => props.theme.colors.textPrimary};
    font-family: 'JetBrains Mono', monospace;
  }

  .label {
    font-size: 0.7rem;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    color: ${props => props.theme.colors.textSecondary};
    font-weight: 800;
  }
`;

const sectors = [
  {
    id: 1,
    sectorId: 'automobile',
    name: 'Automobile',
    icon: '🚗',
    description: 'Leading automotive companies and electric vehicle manufacturers driving the future of transportation.',
    stats: {
      companies: '120+',
      growth: '+8.2%',
      marketCap: '$2.1T'
    }
  },
  {
    id: 2,
    sectorId: 'hospitality',
    name: 'Hospitality',
    icon: '🏨',
    description: 'Hotels, restaurants, travel services and leisure companies shaping the global hospitality industry.',
    stats: {
      companies: '85+',
      growth: '+12.5%',
      marketCap: '$1.8T'
    }
  },
  {
    id: 3,
    sectorId: 'finance',
    name: 'Finance',
    icon: '💼',
    description: 'Financial services, investment firms, insurance companies and fintech innovators transforming finance.',
    stats: {
      companies: '20+',
      growth: '+6.8%',
      marketCap: '$4.5T'
    }
  },
  {
    id: 4,
    sectorId: 'banking',
    name: 'Banking',
    icon: '🏦',
    description: 'Global banking institutions, investment banks and financial intermediaries powering economic growth.',
    stats: {
      companies: '150+',
      growth: '+5.3%',
      marketCap: '$3.9T'
    }
  },
  {
    id: 5,
    sectorId: 'energy',
    name: 'Energy',
    icon: '⚡',
    description: 'Oil, gas, power generation, and renewable energy companies driving global energy infrastructure.',
    stats: {
      companies: '95+',
      growth: '+9.1%',
      marketCap: '$3.2T'
    }
  },
  {
    id: 6,
    sectorId: 'pharma',
    name: 'Pharma',
    icon: '💊',
    description: 'Pharmaceutical companies, biotech firms, and healthcare innovators revolutionizing medicine.',
    stats: {
      companies: '110+',
      growth: '+7.4%',
      marketCap: '$2.8T'
    }
  },
  {
    id: 7,
    sectorId: 'fmcg',
    name: 'FMCG',
    icon: '🛒',
    description: 'Fast-moving consumer goods, food, beverages and personal care brands serving daily needs.',
    stats: {
      companies: '75+',
      growth: '+4.9%',
      marketCap: '$1.5T'
    }
  },
  {
    id: 8,
    sectorId: 'metals',
    name: 'Metals',
    icon: '⛏️',
    description: 'Steel, aluminum, mining and mineral processing companies supplying to global industries.',
    stats: {
      companies: '85+',
      growth: '+11.2%',
      marketCap: '$2.3T'
    }
  },
  {
    id: 9,
    sectorId: 'realty',
    name: 'Realty',
    icon: '🏢',
    description: 'Real estate investment trusts, property developers, and construction companies.',
    stats: {
      companies: '65+',
      growth: '+10.4%',
      marketCap: '$1.9T'
    }
  },
  {
    id: 10,
    sectorId: 'us_stocks',
    name: 'US Stocks',
    icon: '🇺🇸',
    description: 'Direct investment in top US-listed companies like Apple, Microsoft, and Tesla.',
    stats: {
      companies: '20+',
      growth: '+14.2%',
      marketCap: '$30T+'
    }
  }
];

const Stocks: React.FC = () => {
  const navigate = useNavigate();

  return (
    <StocksContainer>
      <PageHeader
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
      >
        <h1>Market Sectors</h1>
        <p>Explore real-time data and analytics across key industrial sectors. Zeus provides deep visibility into market movements and sector-specific trends.</p>
      </PageHeader>

      <SectorsGrid>
        {sectors.map((sector, index) => (
          <SectorCard
            key={sector.id}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: index * 0.1 }}
            onClick={() => navigate(`/stocks/${sector.sectorId}`)}
          >
            <SectorHeader>
              <SectorIcon>{sector.icon}</SectorIcon>
            </SectorHeader>
            <div>
              <SectorName>{sector.name}</SectorName>
              <SectorDescription>{sector.description}</SectorDescription>
            </div>
            <SectorStats>
              <StatItem>
                <div className="label">Entities</div>
                <div className="value">{sector.stats.companies}</div>
              </StatItem>
              <StatItem>
                <div className="label">Growth</div>
                <div className="value" style={{ color: sector.stats.growth.startsWith('+') ? '#10b981' : '#ef4444' }}>
                  {sector.stats.growth}
                </div>
              </StatItem>
              <StatItem>
                <div className="label">Market Cap</div>
                <div className="value">{sector.stats.marketCap}</div>
              </StatItem>
            </SectorStats>
          </SectorCard>
        ))}
      </SectorsGrid>
    </StocksContainer>
  );
};

export default Stocks;
